1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest: empty item list
6	  it("empty item list yields premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // Base premiums per item type
15	  it("plain sword (no modifiers, first quote) yields premium 115 G (100 base + 10 first + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("plain amulet yields premium 71 G (60 + 6 + 5)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it.todo("plain staff yields premium 93 G (80 + 8 + 5)");
30	  it.todo("plain potion yields premium 49 G (40 + 4 + 5)");
31	
32	  // Component pricing (runes / moonstones)
33	  it.todo("1 rune yields premium 33 G (25 + 2.5 first → 27.5 rounded up 28 + 5 = 33)");
34	  it.todo("2 runes yield premium 60 G (50 base + 5 first = 55 + 5 fee = 60)");
35	  it.todo("3 runes yield block discount premium 71 G (60 + 6 + 5)");
36	  it.todo("4 runes yield premium 115 G (100 + 10 + 5, no block — block requires exactly 3)");
37	  it.todo("7 runes yield premium 198 G (175 + 17.5 first → 192.5 + 5 fee = 197.5 rounded up 198)");
38	
39	  // 'Alike' components clarification
40	  it.todo("2 runes + 1 moonstone yields no block: 75 + 7.5 + 5 = 87.5 → 88 G");
41	  it.todo("3 runes + 3 moonstones yields two separate blocks: 120 base → 120 + 12 + 5 = 137 G");
42	
43	  // Individual modifiers
44	  it.todo("cursed sword (newcomer): 165 G (100 + 50 curse + 10 first + 5 fee)");
45	  it.todo("highly enchanted sword (ench 5, newcomer): 100 + 30 + 10 + 5 = 145 G");
46	  it.todo("sword enchantment 4 (newcomer): no high-ench surcharge → 115 G");
47	  it.todo("cursed + enchantment 5 sword: both surcharges apply (100 + 50 + 30 + 10 + 5 = 195 G)");
48	  it.todo("long-standing customer (2 years exactly) gets 20% loyalty discount");
49	  it.todo("customer's second contract gets 15% follow-up discount");
50	
51	  // Multi-item modifier scope
52	  it.todo("cursed sword + plain amulet (newcomer, single contract): 100+60=160 base, +50 curse = 210, +21 first (10% of 210), +5 fee = 236 G");
53	
54	  // Rounding
55	  it.todo("premium rounded up: calculation 197.5 G yields 198 G");
56	  it.todo("payout rounded down: calculation 350.5 yields 350 G");
57	
58	  // Integration examples
59	  it.todo("newcomer with cursed sword (ench 3): premium 165 G");
60	  it.todo("long-standing customer's second contract with cursed sword (ench 7, 3 years): premium 160 G");
61	
62	  // Claim — standard reimbursement
63	  it.todo("regular steel sword (ench 3), damage 500 G: payout 400 G (500 - 100 deductible)");
64	  it.todo("damage to a rune (value 250), damage 200: payout 100 G (200 - 100)");
65	
66	  // Special clauses
67	  it.todo("high enchantment (ench ≥ 8): 50% of damage, then deductible — sword ench 8, damage 1000 → 400 G");
68	  it.todo("dragon-material sword, ench 9, damage 1000: both clauses, 50% wins, 500 - 100 = 400 G");
69	  it.todo("dragon-material sword, ench 5, damage 800: full reimbursement, 800 - 100 = 700 G");
70	  it.todo("steel sword, ench 9, damage 1000: high-ench only, 500 - 100 = 400 G");
71	
72	  // Deductible per damage event
73	  it.todo("dragon attack damages sword 500 and amulet 300: payout 600 G (deductible per item)");
74	
75	  // Multiple same-type items
76	  it.todo("two swords insured: insurance sum 2000, cap 4000");
77	  it.todo("two swords both damaged (two sword damage entries) get separate deductibles");
78	  it.todo("more damage entries of a type than insured items rejected (CLI exits non-zero)");
79	
80	  // Cap exhaustion
81	  it.todo("sword + amulet policy: insurance sum 1600, cap 3200");
82	  it.todo("cursed sword: cap 2000 (based on unmodified insurance value, ignoring premium modifiers)");
83	  it.todo("sword + 3 runes: insurance sum 1750 (block discount affects premium only)");
84	  it.todo("sword cap 2000, two successive 1500 claims: first payout 1400 (cap rem 600), second payout 600 (cap rem 0)");
85	
86	  // Edge cases
87	  it.todo("unknown item type in quote: CLI exits non-zero with stderr message");
88	  it.todo("claim references item not in policy: CLI exits non-zero with stderr message");
89	  it.todo("claim with negative damage amount: CLI exits non-zero with stderr message");
90	});
