1	const PROCESSING_FEE = 5;
2	const FIRST_QUOTE_SURCHARGE_RATE = 0.1;
3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	};
7	
8	type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
9	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
10	
11	const quotePremium = (items: Array<{ type: string }>): number => {
12	  if (items.length === 0) return PROCESSING_FEE;
13	  const basePrice = BASE_PRICE_BY_TYPE[items[0].type];
14	  return basePrice + basePrice * FIRST_QUOTE_SURCHARGE_RATE + PROCESSING_FEE;
15	};
16	
17	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
18	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
19	  return { results };
20	};
